<html>
<head>
  <script>
    // Anti-loop: throttle programmatic reloads to max 1/10s.
    // User-initiated reload (Cmd+R, address-bar Enter) is unaffected
    // because browser bypasses this property.
    (function () {
      const orig = window.location.reload.bind(window.location);
      let last = 0;
      window.location.reload = function (...args) {
        const now = Date.now();
        if (now - last < 10000) {
          console.warn('[anti-loop] blocked reload (within 10s of previous)');
          return;
        }
        last = now;
        return orig(...args);
      };
    })();
  </script>
  ...
</head>
