// Manifesto dane: { text: "Governance.", accentText: " AI." }
const accentText = line.accentText?.trim() ?? "";
const fullText = accentText ? `${line.text} ${accentText}` : line.text;
const accentFrom = accentText ? line.text.length + 1 : undefined; // +1 dla spacji

<CsLetterReveal
  text={fullText}
  entryRange={entryRange}
  exitRange={exitRange}
  accentFrom={accentFrom}
/>
```

W `CsLetterChar`: `accent` prop → `color: "var(--color-orange)"` na inner span.

```tsx
// CsLetterChar - accent color via inline style (nie CSS inheritance — override)
